import React from "react";
import AnimatedSection from "./AnimatedSection";

const VisionSection = () => {
  return (
    <AnimatedSection
      style={{
        display: "flex",
        alignItems: "center",
        gap: "2rem",
        flexWrap: "wrap",
      }}
    >
      {/* Imagen a la izquierda */}
      <div style={{ flex: 1, minWidth: "320px" }}>
        <img
          src={require("../../assets/quien-contra-nosotros.jpg")}
          alt="Hydrant drink lineup"
          style={{ width: "100%", borderRadius: "1rem", boxShadow: "0 0 15px rgba(0,0,0,0.15)" }}
        />
      </div>

      {/* Texto a la derecha */}
      <div style={{ flex: 1, minWidth: "320px" }}>
        <h3
          style={{
            textTransform: "uppercase",
            color: "#00509e",
            marginBottom: "0.5rem",
            fontSize: "1.1rem",
          }}
        >
          The Problem
        </h3>
        <h2
          style={{
            fontWeight: "900",
            fontSize: "2.5rem",
            marginBottom: "1rem",
            color: "#003E73",
          }}
        >
          Dehydration, the hidden foe
        </h2>
        <p
          style={{
            fontSize: "1.3rem",
            lineHeight: "1.6",
            color: "#003E73",
          }}
        >
          Everyday for both of us was plagued by classic burnout—frequent headaches, lack of focus, and low energy.
          Without knowing it, dehydration had reared its ugly head and controlled our every move. Gallons of water
          we chugged at our respective jobs couldn’t save us. We needed a new hero.
        </p>
      </div>
    </AnimatedSection>
  );
};

export default VisionSection;
